base='http://localhost:80/'
candidates=['encode.php','encoder.php','encoder64.php','base64.php','utils.php','utility.php','tool.php','tools.php','converter.php','convert.php','filter.php','view.php','template.php','render.php','page.php','blog.php','article.php','post','post?','post.php','posts.php','feed.php','rss.php','sitemap.php','search.php','query.php','admin/','admin/index.php','admin/login.php','upload','uploads','image.php','img.php','static/images/','static/js/','static/css/']
